1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = {
13	  type: string;
14	  material?: string;
15	  enchantment?: number;
16	  cursed?: boolean;
17	};
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Damage = { itemType: string; amount: number };
20	type ClaimStep = {
21	  op: "claim";
22	  policy: number;
23	  incident: { cause: string; damages: Damage[] };
24	};
25	type Step = QuoteStep | ClaimStep;
26	type Customer = { yearsWithMHPCO: number };
27	type Scenario = { customer: Customer; steps: Step[] };
28	
29	const BLOCK_SIZE = 3;
30	const BLOCK_PREMIUM = 60;
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	
33	const CURSED_RATE = 0.5;
34	const HIGH_ENCHANTMENT_THRESHOLD = 5;
35	const HIGH_ENCHANTMENT_RATE = 0.3;
36	
37	type Rule<T> = { applies: (subject: T) => boolean; rate: number };
38	
39	const sumApplicableRates = <T>(rules: Rule<T>[], subject: T): number =>
40	  rules
41	    .filter((rule) => rule.applies(subject))
42	    .reduce((sum, rule) => sum + rule.rate, 0);
43	
44	const isCursed = (item: Item): boolean => item.cursed === true;
45	const isHighlyEnchanted = (item: Item): boolean =>
46	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
47	
48	const SURCHARGE_RULES: Rule<Item>[] = [
49	  { applies: isCursed, rate: CURSED_RATE },
50	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
51	];
52	
53	const groupByType = (items: Item[]): Map<string, Item[]> => {
54	  const groups = new Map<string, Item[]>();
55	  for (const item of items) {
56	    const group = groups.get(item.type) ?? [];
57	    group.push(item);
58	    groups.set(item.type, group);
59	  }
60	  return groups;
61	};
62	
63	const basePremiumFor = (type: string) => {
64	  const base = BASE_PREMIUM[type];
65	  if (base === undefined) throw new Error(`Unknown item type: ${type}`);
66	  return base;
67	};
68	
69	const premiumForGroup = (type: string, group: Item[]) => {
70	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
71	    return BLOCK_PREMIUM;
72	  }
73	  return group.length * basePremiumFor(type);
74	};
75	
76	const surchargeForItem = (item: Item) =>
77	  basePremiumFor(item.type) * sumApplicableRates(SURCHARGE_RULES, item);
78	
79	const policyBasePremium = (items: Item[]) =>
80	  [...groupByType(items)].reduce(
81	    (total, [type, group]) => total + premiumForGroup(type, group),
82	    0,
83	  );
84	
85	const totalItemSurcharges = (items: Item[]) =>
86	  items.reduce((sum, item) => sum + surchargeForItem(item), 0);
87	
88	const FIRST_INSURANCE_RATE = 0.1;
89	const LOYALTY_THRESHOLD_YEARS = 2;
90	const LOYALTY_RATE = 0.2;
91	const FOLLOWUP_RATE = 0.15;
92	
93	type QuoteContext = { customer: Customer; stepIndex: number };
94	
95	const POLICY_ADJUSTMENTS: Rule<QuoteContext>[] = [
96	  { applies: () => true, rate: FIRST_INSURANCE_RATE },
97	  {
98	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
99	    rate: -LOYALTY_RATE,
100	  },
101	  { applies: ({ stepIndex }) => stepIndex > 0, rate: -FOLLOWUP_RATE },
102	];
103	
104	const policyAdjustment = (ctx: QuoteContext, policyBase: number) =>
105	  policyBase * sumApplicableRates(POLICY_ADJUSTMENTS, ctx);
106	
107	const quote = (step: QuoteStep, customer: Customer, stepIndex: number) => {
108	  const { items } = step;
109	  const policyBase = policyBasePremium(items);
110	  const premium =
111	    policyBase +
112	    policyAdjustment({ customer, stepIndex }, policyBase) +
113	    totalItemSurcharges(items);
114	  return { premium: Math.ceil(premium) + PROCESSING_FEE };
115	};
116	
117	const INSURANCE_VALUE: Record<string, number> = {
118	  sword: 1000,
119	  amulet: 600,
120	  staff: 800,
121	  potion: 400,
122	  rune: 250,
123	  moonstone: 250,
124	};
125	const DEDUCTIBLE = 100;
126	const CAP_MULTIPLIER = 2;
127	
128	const insuranceSum = (items: Item[]) =>
129	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
130	
131	const payoutForDamage = (damage: Damage) =>
132	  Math.max(0, damage.amount - DEDUCTIBLE);
133	
134	type PolicyState = { items: Item[]; remainingCap: number };
135	
136	const totalPayout = (damages: Damage[]) =>
137	  damages.reduce((sum, d) => sum + payoutForDamage(d), 0);
138	
139	const newPolicy = (items: Item[]): PolicyState => ({
140	  items,
141	  remainingCap: insuranceSum(items) * CAP_MULTIPLIER,
142	});
143	
144	const claim = (step: ClaimStep, policies: PolicyState[]) => {
145	  const policy = policies[step.policy];
146	  const payout = totalPayout(step.incident.damages);
147	  policy.remainingCap -= payout;
148	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
149	};
150	
151	export const run = (input: Scenario): unknown => {
152	  const policies: PolicyState[] = [];
153	  const results = input.steps.map((step, i) => {
154	    if (step.op === "quote") {
155	      policies[i] = newPolicy(step.items);
156	      return quote(step, input.customer, i);
157	    }
158	    return claim(step, policies);
159	  });
160	  return { results };
161	};
